INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4481fe02-a71f-422d-afc7-1b3539e3be61',
  '00000000-0000-0000-0000-000000000001',
  $escape$csharp_game — Embedding Lua for Efficient Game Scripting$escape$,
  $escape$csharp_game developers often leverage Lua for scripting due to its ease of use and flexibility. By embedding Lua, game developers can create sandboxed environments for scripting, utilizing metatables to manage and restrict access to game objects. This approach allows for efficient and secure scripting. The Lua.NET library provides a straightforward way to integrate Lua into csharp_game projects, enabling developers to execute Lua scripts and interact with the game environment.$escape$,
  $escape$using LuaNET;
Lua lua = new Lua();
lua.DoString("print('Hello, World!')");$escape$,
  $escape$csharp$escape$,
