INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9b503185-14fe-486f-b3db-235bc50c2d53',
  '00000000-0000-0000-0000-000000000001',
  $escape$csharp_game: Mastering Coroutines with Unity's WaitForSeconds$escape$,
  $escape$When building games with csharp_game, efficient async programming is crucial. Unity's coroutines provide a simple way to write asynchronous code. By using WaitForSeconds, you can pause coroutine execution for a specified duration. This allows for seamless implementation of timed events, animations, and AI behaviors. For example, you can create a coroutine that waits for 2 seconds before spawning an enemy. To use WaitForSeconds, simply yield return it within your coroutine. This pattern is particularly useful in games where timing is critical, such as in puzzle games or rhythm games.$escape$,
  $escape$IEnumerator SpawnEnemy() { yield return new WaitForSeconds(2); Instantiate(enemyPrefab); }$escape$,
  $escape$csharp$escape$,
