INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '20591e14-9a05-4e2b-a986-acde987a291b',
  '00000000-0000-0000-0000-000000000001',
  $escape$csharp_game Math Library Usage — Efficient Vector and Quaternion Operations$escape$,
  $escape$csharp_game's math library provides efficient operations for vectors, matrices, and quaternions. Vectors are represented by the Vector3 struct, which offers methods like Normalize(), Scale(), and Dot(). Quaternions, represented by the Quaternion struct, provide methods like Normalize(), Multiply(), and Slerp() for interpolation. Matrices are represented by the Matrix4x4 struct, which offers methods like Multiply() and Invert(). Interpolation between vectors and quaternions can be achieved using the Lerp() and Slerp() methods, respectively.$escape$,
  $escape$Vector3 v1 = new Vector3(1, 2, 3); Vector3 v2 = new Vector3(4, 5, 6); Vector3 result = Vector3.Lerp(v1, v2, 0.5f);$escape$,
  $escape$csharp$escape$,
