INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '02b29842-4d6d-41e9-bb9f-e156b7d11704',
  '00000000-0000-0000-0000-000000000001',
  $escape$csharp_game Memory Management: Efficient Pooling and Avoiding Mid-Frame Allocation$escape$,
  $escape$In Unity, csharp_game scripts run on the managed heap, which can lead to garbage collection pauses. To mitigate this, use object pooling to reuse objects instead of allocating new ones. Implement a pool by creating a list to store inactive objects and a method to retrieve or create objects as needed. Avoid mid-frame allocation by pre-allocating objects during initialization or loading phases. Unity's Profiler can help identify allocation hotspots.$escape$,
  $escape$public class ObjectPool<T> where T : new() { private List<T> inactiveObjects = new List<T>(); public T GetObject() { if (inactiveObjects.Count > 0) { T obj = inactiveObjects[0]; inactiveObjects.RemoveAt(0); return obj; } else { return new T(); } } public void ReturnObject(T obj) { inactiveObjects.Add(obj); } }$escape$,
  $escape$csharp$escape$,
